#ifndef KERNEL_H
#define KERNEL_H

#include <torch/extension.h>
#include <cuda_runtime.h>
#include <stdint.h>

// Host function declarations
torch::Tensor run(torch::Tensor probs, torch::Tensor top_k, torch::Tensor top_p, torch::Tensor samples);

// CUDA kernel declarations
__global__ void prepare_keys_kernel(const float* __restrict__ probs, uint32_t* __restrict__ keys, int64_t batch_size, int64_t vocab_size);
__global__ void sample_kernel(
    const uint32_t* __restrict__ sorted_keys, 
    const int64_t* __restrict__ sorted_indices,
    const int32_t* __restrict__ top_k,
    const float* __restrict__ top_p,
    int64_t* __restrict__ samples,
    int64_t batch_size,
    int64_t vocab_size
);

// Host function to sort rows using CUB
void sort_rows(uint32_t* d_keys, int64_t* d_indices, int64_t batch_size, int64_t vocab_size, const int* d_offsets, cudaStream_t stream);

// Wrapper function for CUDA operations
void execute_sampling(const float* d_probs, const int32_t* d_top_k, const float* d_top_p, int64_t* d_samples, int64_t batch_size, int64_t vocab_size, cudaStream_t stream);

#endif // KERNEL_H

#include <cuda_runtime.h>
#include <math_constants.h>
#include <cub/cub.cuh>
#include <device_launch_parameters.h>
#include <cooperative_groups.h>

namespace cg = cooperative_groups;

// Simple Xorshift64 RNG for sampling
__device__ __forceinline__ uint64_t xorshift64(uint64_t& state) {
    state ^= state << 13;
    state ^= state >> 7;
    state ^= state << 17;
    return state;
}

__device__ __forceinline__ float rand_float(uint64_t& state) {
    return (xorshift64(state) >> 11) * (1.0f / 9007199254740992.0f);
}

// Kernel to convert float probabilities to inverted uint32 keys for sorting
__global__ void prepare_keys_kernel(const float* __restrict__ probs, uint32_t* __restrict__ keys, int64_t batch_size, int64_t vocab_size) {
    int64_t idx = blockIdx.x * blockDim.x + threadIdx.x;
    int64_t total = batch_size * vocab_size;
    if (idx < total) {
        float p = probs[idx];
        // Cast float to uint32 bit representation
        uint32_t u = __float_as_uint(p);
        // Invert bits to reverse sort order (since probs are positive)
        keys[idx] = ~u;
    }
}

// Host function to sort rows using CUB
void sort_rows(uint32_t* d_keys, int64_t* d_indices, int64_t batch_size, int64_t vocab_size, const int* d_offsets, cudaStream_t stream) {
    void* d_temp_storage = nullptr;
    size_t temp_storage_bytes = 0;

    // Use int for CUB API compatibility
    int num_items = static_cast<int>(batch_size * vocab_size);
    int num_segments = static_cast<int>(batch_size);

    // Create temporary buffers for ping-pong
    uint32_t* d_keys_temp = nullptr;
    int64_t* d_indices_temp = nullptr;

    cudaError_t err = cudaMalloc(&d_keys_temp, num_items * sizeof(uint32_t));
    if (err != cudaSuccess) {
        return;
    }
    err = cudaMalloc(&d_indices_temp, num_items * sizeof(int64_t));
    if (err != cudaSuccess) {
        cudaFree(d_keys_temp);
        return;
    }

    // Initialize DoubleBuffer with two pointers (data and temp)
    cub::DoubleBuffer<uint32_t> d_keys_buf(d_keys, d_keys_temp);
    cub::DoubleBuffer<int64_t> d_indices_buf(d_indices, d_indices_temp);

    // First call to get temp storage size
    err = cub::DeviceSegmentedRadixSort::SortPairs(
        d_temp_storage, 
        temp_storage_bytes,
        d_keys_buf,
        d_indices_buf,
        num_items,
        num_segments,
        d_offsets,
        d_offsets + num_segments,
        0, 31,  // bits (0 to 31 for uint32)
        stream
    );

    if (err != cudaSuccess) {
        cudaFree(d_keys_temp);
        cudaFree(d_indices_temp);
        return;
    }

    if (temp_storage_bytes > 0) {
        err = cudaMalloc(&d_temp_storage, temp_storage_bytes);
        if (err != cudaSuccess) {
            cudaFree(d_keys_temp);
            cudaFree(d_indices_temp);
            return;
        }

        // Second call to perform sort
        err = cub::DeviceSegmentedRadixSort::SortPairs(
            d_temp_storage, 
            temp_storage_bytes,
            d_keys_buf,
            d_indices_buf,
            num_items,
            num_segments,
            d_offsets,
            d_offsets + num_segments,
            0, 31,
            stream
        );

        cudaFree(d_temp_storage);
    }

    // Free temp buffers
    cudaFree(d_keys_temp);
    cudaFree(d_indices_temp);
}

// Kernel to apply Top-K/Top-P logic and sample
__global__ void sample_kernel(
    const uint32_t* __restrict__ sorted_keys, 
    const int64_t* __restrict__ sorted_indices,
    const int32_t* __restrict__ top_k,
    const float* __restrict__ top_p,
    int64_t* __restrict__ samples,
    int64_t batch_size,
    int64_t vocab_size
) {
    int64_t batch_idx = blockIdx.x;
    if (batch_idx >= batch_size) return;

    // Pointers to the current row's sorted data
    const uint32_t* row_keys = sorted_keys + batch_idx * vocab_size;
    const int64_t* row_indices = sorted_indices + batch_idx * vocab_size;

    int32_t k = top_k[batch_idx];
    float p = top_p[batch_idx];

    // Seed RNG with batch_idx
    uint64_t state = (uint64_t)(batch_idx) * 123456789 + 1;

    // Handle edge cases
    if (p <= 0.0f) {
        // Argmax (first element in sorted list)
        samples[batch_idx] = row_indices[0];
        return;
    }

    // Determine effective K limit
    int64_t limit_k = k;
    if (limit_k <= 0 || limit_k >= vocab_size) {
        limit_k = vocab_size;
    }

    // Optimization: If p is 1.0, we don't need Top-P scan, just Top-K
    bool use_top_p = (p < 1.0f);

    // Pass 1: Sum top K probabilities
    float thread_sum = 0.0f;
    int64_t scan_limit = limit_k;

    for (int64_t i = threadIdx.x; i < scan_limit; i += blockDim.x) {
        uint32_t key = row_keys[i];
        float val = __uint_as_float(~key);
        thread_sum += val;
    }

    // Warp-level reduction for sum_k
    __shared__ float s_sum_k[256];
    s_sum_k[threadIdx.x] = thread_sum;
    __syncthreads();

    for (int stride = 128; stride > 0; stride >>= 1) {
        if (threadIdx.x < stride) {
            s_sum_k[threadIdx.x] += s_sum_k[threadIdx.x + stride];
        }
        __syncthreads();
    }
    float total_sum_k = s_sum_k[0];

    if (total_sum_k == 0.0f) {
        samples[batch_idx] = row_indices[0];
        return;
    }

    // Threshold for Top-P
    float threshold = p * total_sum_k;
    int64_t final_cutoff = scan_limit;

    // Pass 2: Find P cutoff (cumsum > threshold)
    // We use Thread 0 to perform the linear scan for correctness and simplicity
    if (threadIdx.x == 0) {
        if (use_top_p) {
            float running = 0.0f;
            for (int64_t i = 0; i < scan_limit; ++i) {
                uint32_t key = row_keys[i];
                float val = __uint_as_float(~key);
                running += val;
                if (running > threshold) {
                    final_cutoff = i;
                    break;
                }
            }
        }
    }
    __syncthreads();

    // Broadcast cutoff_idx (Thread 0 has it)
    __shared__ int64_t s_cutoff;
    if (threadIdx.x == 0) {
        s_cutoff = final_cutoff;
    }
    __syncthreads();
    int64_t cutoff = s_cutoff;

    // Final limit is min(cutoff + 1, scan_limit) because cutoff is the index where cumsum > threshold
    // So we include indices 0 to cutoff inclusive.
    int64_t final_limit = (cutoff + 1 < scan_limit) ? (cutoff + 1) : scan_limit;

    // Pass 3: Sample
    // Compute sum for the final range
    float final_sum = 0.0f;
    for (int64_t i = threadIdx.x; i < final_limit; i += blockDim.x) {
        uint32_t key = row_keys[i];
        float val = __uint_as_float(~key);
        final_sum += val;
    }

    // Reduction for final_sum
    s_sum_k[threadIdx.x] = final_sum;
    __syncthreads();
    for (int stride = 128; stride > 0; stride >>= 1) {
        if (threadIdx.x < stride) {
            s_sum_k[threadIdx.x] += s_sum_k[threadIdx.x + stride];
        }
        __syncthreads();
    }
    final_sum = s_sum_k[0];

    if (final_sum == 0.0f) {
        samples[batch_idx] = row_indices[0];
        return;
    }

    // Sample
    // Only one thread needs to do the sampling to avoid race conditions on samples[batch_idx]
    if (threadIdx.x == 0) {
        float r = rand_float(state) * final_sum;
        float running = 0.0f;
        int64_t selected_idx = 0;
        for (int64_t i = 0; i < final_limit; ++i) {
            uint32_t key = row_keys[i];
            float val = __uint_as_float(~key);
            running += val;
            if (running > r) {
                selected_idx = i;
                break;
            }
        }
        samples[batch_idx] = row_indices[selected_idx];
    }
}

// Wrapper function for CUDA operations
void execute_sampling(const float* d_probs, const int32_t* d_top_k, const float* d_top_p, int64_t* d_samples, int64_t batch_size, int64_t vocab_size, cudaStream_t stream) {
    // Allocate temporary buffers for sorting
    uint32_t* d_keys = nullptr;
    int64_t* d_indices = nullptr;
    int* d_offsets = nullptr;

    cudaError_t err;
    err = cudaMalloc(&d_keys, batch_size * vocab_size * sizeof(uint32_t));
    if (err != cudaSuccess) return;

    err = cudaMalloc(&d_indices, batch_size * vocab_size * sizeof(int64_t));
    if (err != cudaSuccess) {
        cudaFree(d_keys);
        return;
    }

    err = cudaMalloc(&d_offsets, (batch_size + 1) * sizeof(int));
    if (err != cudaSuccess) {
        cudaFree(d_keys);
        cudaFree(d_indices);
        return;
    }

    // Initialize indices (0 to vocab_size-1) for each batch item
    int64_t* h_indices = new int64_t[vocab_size];
    for (int64_t i = 0; i < vocab_size; ++i) {
        h_indices[i] = i;
    }

    // Copy indices to device for each batch
    for (int64_t i = 0; i < batch_size; ++i) {
        err = cudaMemcpy(d_indices + i * vocab_size, h_indices, vocab_size * sizeof(int64_t), cudaMemcpyHostToDevice);
        if (err != cudaSuccess) {
            delete[] h_indices;
            cudaFree(d_keys);
            cudaFree(d_indices);
            cudaFree(d_offsets);
            return;
        }
    }
    delete[] h_indices;

    // Prepare segment offsets for CUB (0, vocab_size, 2*vocab_size, ...)
    int* h_offsets = new int[batch_size + 1];
    for (int64_t i = 0; i <= batch_size; ++i) {
        h_offsets[i] = static_cast<int>(i * vocab_size);
    }
    err = cudaMemcpy(d_offsets, h_offsets, (batch_size + 1) * sizeof(int), cudaMemcpyHostToDevice);
    if (err != cudaSuccess) {
        delete[] h_offsets;
        cudaFree(d_keys);
        cudaFree(d_indices);
        cudaFree(d_offsets);
        return;
    }
    delete[] h_offsets;

    // Prepare keys kernel
    int threads = 256;
    int blocks = (batch_size * vocab_size + threads - 1) / threads;
    prepare_keys_kernel<<<blocks, threads, 0, stream>>>(
        d_probs,
        d_keys,
        batch_size,
        vocab_size
    );

    // Sort using CUB
    sort_rows(d_keys, d_indices, batch_size, vocab_size, d_offsets, stream);

    // Launch sampling kernel
    int sample_threads = 256;
    sample_kernel<<<batch_size, sample_threads, 0, stream>>>(
        d_keys,
        d_indices,
        d_top_k,
        d_top_p,
        d_samples,
        batch_size,
        vocab_size
    );

    // Free temporary buffers
    cudaFree(d_keys);
    cudaFree(d_indices);
    cudaFree(d_offsets);
}

#include <torch/extension.h>
#include <cuda_runtime.h>
#include <c10/cuda/CUDAGuard.h>
#include <vector>
#include <iostream>
#include "kernel.h"

// Helper to check CUDA errors
#define CUDA_CHECK(call) \
    do { \
        cudaError_t err = call; \
        if (err != cudaSuccess) { \
            std::cerr << "CUDA error at " << __FILE__ << ":" << __LINE__ << ": " << cudaGetErrorString(err) << std::endl; \
            throw std::runtime_error("CUDA kernel launch failed"); \
        } \
    } while(0)

// Host function to run the sampling
torch::Tensor run(torch::Tensor probs, torch::Tensor top_k, torch::Tensor top_p, torch::Tensor samples) {
    // Validate inputs
    TORCH_CHECK(probs.is_cuda(), "probs must be a CUDA tensor");
    TORCH_CHECK(top_k.is_cuda(), "top_k must be a CUDA tensor");
    TORCH_CHECK(top_p.is_cuda(), "top_p must be a CUDA tensor");
    TORCH_CHECK(samples.is_cuda(), "samples must be a CUDA tensor");
    TORCH_CHECK(probs.dtype() == torch::kFloat32, "probs must be float32");
    TORCH_CHECK(top_k.dtype() == torch::kInt32, "top_k must be int32");
    TORCH_CHECK(top_p.dtype() == torch::kFloat32, "top_p must be float32");
    TORCH_CHECK(samples.dtype() == torch::kInt64, "samples must be int64");

    int64_t batch_size = probs.size(0);
    int64_t vocab_size = probs.size(1);

    TORCH_CHECK(vocab_size == 151936, "vocab_size must be 151936");
    TORCH_CHECK(top_k.size(0) == batch_size, "top_k size mismatch");
    TORCH_CHECK(top_p.size(0) == batch_size, "top_p size mismatch");
    TORCH_CHECK(samples.size(0) == batch_size, "samples size mismatch");

    if (batch_size == 0) {
        return samples;
    }

    // Get CUDA stream
    cudaStream_t stream = c10::cuda::getCurrentCUDAStream();

    // Execute sampling using wrapper function
    execute_sampling(
        probs.data_ptr<float>(),
        top_k.data_ptr<int32_t>(),
        top_p.data_ptr<float>(),
        samples.data_ptr<int64_t>(),
        batch_size,
        vocab_size,
        stream
    );

    // Synchronize to ensure completion before returning
    CUDA_CHECK(cudaDeviceSynchronize());

    return samples;
}

PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
    m.def("run", &run, "Top-K/Top-P Sampling Kernel");
}
